import { useParams, useNavigate } from "react-router-dom";
import { useEffect, useState } from "react";

function OfferLetter() {
  const { applicationId } = useParams();
  const navigate = useNavigate();

  const [application, setApplication] = useState(null);

  const [salary, setSalary] = useState("");
  const [joiningDate, setJoiningDate] = useState("");
  const [location, setLocation] = useState("");
  const [notes, setNotes] = useState("");

  /* =========================
     LOAD APPLICATION
  ========================= */
  useEffect(() => {
    const apps =
      JSON.parse(localStorage.getItem("applications")) || [];

    setApplication(
      apps.find(
        (a) => String(a.id) === String(applicationId)
      )
    );
  }, [applicationId]);

  /* =========================
     LOAD OFFER (EDIT MODE)
  ========================= */
  useEffect(() => {
    const offers =
      JSON.parse(localStorage.getItem("offerLetters")) || [];

    const offer = offers.find(
      (o) => String(o.applicationId) === String(applicationId)
    );

    if (offer) {
      setSalary(offer.salary);
      setJoiningDate(offer.joiningDate);
      setLocation(offer.location);
      setNotes(offer.notes || "");
    }
  }, [applicationId]);

  /* =========================
     SAVE OFFER
  ========================= */
  const handleSaveOffer = () => {
    if (!salary || !joiningDate || !location) {
      alert("All fields are required");
      return;
    }

    const offers =
      JSON.parse(localStorage.getItem("offerLetters")) || [];

    const filtered = offers.filter(
      (o) => String(o.applicationId) !== String(applicationId)
    );

    const newOffer = {
      applicationId,
      name: application.employeeName,
      email: application.email,
      jobTitle: application.jobTitle,
      salary,
      joiningDate,
      offerDate: new Date().toISOString().split("T")[0],
      location,
      notes,
      status: "OFFER_SENT",
    };

    filtered.push(newOffer);
    localStorage.setItem(
      "offerLetters",
      JSON.stringify(filtered)
    );

    const applications =
      JSON.parse(localStorage.getItem("applications")) || [];

    const updatedApplications = applications.map((a) =>
      String(a.id) === String(applicationId)
        ? { ...a, status: "OFFER_SENT" }
        : a
    );

    localStorage.setItem(
      "applications",
      JSON.stringify(updatedApplications)
    );

    navigate("/dashboard/view-applicants");
  };

  if (!application) return <p>Loading...</p>;

  return (
    <div style={{ marginTop: "25px", maxWidth: "600px" }}>
      <h2>Generate Offer Letter</h2>

      <p><b>Name:</b> {application.employeeName}</p>
      <p><b>Email:</b> {application.email}</p>
      <p><b>Job Title:</b> {application.jobTitle}</p>

      <hr />

      <input
        type="number"
        placeholder="Annual Salary"
        value={salary}
        onChange={(e) => setSalary(e.target.value)}
      />

      <input
        type="date"
        value={joiningDate}
        onChange={(e) => setJoiningDate(e.target.value)}
      />

      <input
        type="text"
        placeholder="Work Location"
        value={location}
        onChange={(e) => setLocation(e.target.value)}
      />

      <textarea
        placeholder="Notes (optional)"
        value={notes}
        onChange={(e) => setNotes(e.target.value)}
      />

      <button onClick={handleSaveOffer}>
        Save Offer Letter
      </button>
    </div>
  );
}

export default OfferLetter;
